using System;

class Program
{
    static void Main(string[] args)
    {
        string[] fruits = { "Alma", "Armud", "Banan", "Çiyələk" };

        foreach (string fruit in fruits)
        {
            Console.WriteLine($"Meyvə: {fruit}");
        }
    }
}
// Output:
// Meyvə: Alma
// Meyvə: Armud
// Meyvə: Banan
// Meyvə: Çiyələk

