using System;

class Program
{
    static void Main(string[] args)
    {
        int[] numbers = { 1, 2, 3, 4, 5 };

        foreach (int number in numbers)
        {
            if (number == 3)
            {
                continue; // 3-ü atlayır
            }
            if (number == 5)
            {
                break; // Dövrü dayandırır
            }
            Console.WriteLine($"Rəqəm: {number}");
        }
    }
}
// Output:
// Rəqəm: 1
// Rəqəm: 2
// Rəqəm: 4

